const data = $json["Global Quote"];

const price = parseFloat(data["05. price"]);
const change = parseFloat(data["09. change"]);
const changePercent = parseFloat(data["10. change percent"]);

let trend = "Neutral";
if (change > 0) trend = "Bullish";
if (change < 0) trend = "Bearish";

// Volatility
let volatility = "Low";
if (Math.abs(changePercent) > 1) volatility = "High";
else if (Math.abs(changePercent) > 0.5) volatility = "Medium";

// Strategy + Allocation
let strategy = "";
let allocation = {};

if (trend === "Bullish" && volatility === "Low") {
  strategy = "Stable growth investing";
  allocation = { Equity: "70%", Debt: "20%", Gold: "10%" };
} else if (trend === "Bullish" && volatility === "High") {
  strategy = "Aggressive growth investing";
  allocation = { Equity: "80%", Debt: "10%", Gold: "10%" };
} else if (trend === "Bearish") {
  strategy = "Defensive investing (capital protection)";
  allocation = { Equity: "40%", Debt: "40%", Gold: "20%" };
} else {
  strategy = "Balanced investing";
  allocation = { Equity: "60%", Debt: "30%", Gold: "10%" };
}

return [{
  ...$json,
  marketPrice: price,
  marketChange: change,
  marketChangePercent: changePercent + "%",
  marketTrend: trend,
  volatility,
  recommendedStrategy: strategy,
  allocation
}];
